<fieldset class="border p-3 mb-3"><legend class="w-auto px-2 fs-6">Watermark Settings</legend><div class="row"><div class="col-md-4 mb-3"><label class="form-label">Watermark <span class="badge bg-secondary ms-1">Optional</span></label><select name="watermark_enabled" class="form-select"><option value="0" {{ ($watermarkEnabled??0)==0?"selected":"" }}>Disabled</option><option value="1" {{ ($watermarkEnabled??0)==1?"selected":"" }}>Enabled</option></select></div><div class="col-md-4 mb-3"><label class="form-label">Position <span class="badge bg-secondary ms-1">Optional</span></label><select name="watermark_position" class="form-select">@foreach(["center"=>"Center","top-left"=>"Top Left","top-right"=>"Top Right","bottom-left"=>"Bottom Left","bottom-right"=>"Bottom Right"] as $val=>$lab)<option value="{{ $val }}" {{ ($position??"center")===$val?"selected":"" }}>{{ $lab }}</option>@endforeach</select></div><div class="col-md-4 mb-3"><label class="form-label">Opacity <span class="badge bg-secondary ms-1">Optional</span></label><input type="number" name="watermark_opacity" class="form-control" step="0.1" min="0" max="1" value="{{ $opacity??0.4 }}"></div></div></fieldset>